generated_oml:
// C3: Physical sensing components
instance MotorMountedEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑mounted encoder providing angular position measurements of the motor shaft"
    DTDFVocab:producedData MotorPositionTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox providing angular position measurements of the gearbox output"
    DTDFVocab:producedData GearboxPositionTransmitted
]

instance RobotControllerInterface : DTDFVocab:SensingComponent [
    base:desc "Robot controller supplying motor current I_M and output angle measurements"
    DTDFVocab:producedData ControllerCurrentTransmitted
    DTDFVocab:producedData ControllerOutputAngleTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorPositionTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorMountedEncoder
]

instance GearboxPositionTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance ControllerCurrentTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom RobotControllerInterface
]

instance ControllerOutputAngleTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom RobotControllerInterface
]

// C10: Data
instance MotorPositionData : DTDFVocab:Data [
    base:desc "Time series of motor shaft angular position streamed via MQTT"
    DTDFVocab:inputTo MQTTBroker
    DTDFVocab:fromData MotorPositionTransmitted
]

instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Time series of gearbox output angular position streamed via MQTT"
    DTDFVocab:inputTo MQTTBroker
    DTDFVocab:fromData GearboxPositionTransmitted
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Motor phase current I_M streamed via MQTT"
    DTDFVocab:inputTo MQTTBroker
    DTDFVocab:fromData ControllerCurrentTransmitted
]

instance OutputAngleData : DTDFVocab:Data [
    base:desc "Robot controller output angle streamed via MQTT"
    DTDFVocab:inputTo MQTTBroker
    DTDFVocab:fromData ControllerOutputAngleTransmitted
]

// C11: Enablers
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used for live streaming of sensor measurements to the digital shadow"
    DTDFVocab:enables FrictionIdentificationService, DataVisualizationService
]

instance MATLABSimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink runtime executing friction‑free and friction‑augmented simulation models"
    DTDFVocab:enables FrictionIdentificationService, ModelParameterUpdateService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "AAS providing standardized interface for feeding identified friction parameters back to the robot controller"
    DTDFVocab:enables ModelParameterUpdateService
]

instance DashboardVisualizationTool : DTDFVocab:Enabler [
    base:desc "Custom dashboard visualising measured vs. simulated data in real time"
    DTDFVocab:enables DataVisualizationService
]

instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc "SysML tooling used for structural block definition and internal block diagrams of the robot axis"
    DTDFVocab:enables AssetModelService
]

// C6: Services
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of static, kinetic and viscous friction coefficients for the gearbox"
    DTDFVocab:provides FrictionParameterInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Unified dashboard visualising live measured data against simulated traces"
    DTDFVocab:provides VisualizationInsight
]

instance ModelParameterUpdateService : DTDFVocab:Service [
    base:desc "Updates friction model parameters in the robot controller to improve motion accuracy"
    DTDFVocab:provides ModelParameterUpdateAction
]

instance AssetModelService : DTDFVocab:Service [
    base:desc "Provides asset modeling capabilities for the SysML toolchain"
]

// C17: Insights / Actions
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Derived static, kinetic and viscous friction coefficients obtained from live sensor data"
]

instance VisualizationInsight : DTDFVocab:Insight [
    base:desc "Comparison of measured angular positions and currents with simulated traces showing model fidelity"
]

instance ModelParameterUpdateAction : DTDFVocab:Action [
    base:desc "Feeds identified friction coefficients back to the robot controller for motion control refinement"
    DTDFVocab:IsAutomatic true
]

// C10: Models / Data
instance SysMLAxisStructureModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagram describing the MABI MAX 100 first axis structure"
    DTDFVocab:inputTo SysMLModelingTool
]

instance FrictionFreeSimModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model representing friction‑free dynamic behavior of the axis"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance FrictionAugmentedSimModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model including static, kinetic and viscous friction parameters for the gearbox"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance TorqueComputationModel : DTDFVocab:Model [
    base:desc "Data calculation model that computes derived torque τ from current and motor parameters"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance VelocityComputationModel : DTDFVocab:Model [
    base:desc "Data calculation model that derives angular velocity ω from consecutive position measurements"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

// C8: Component & Environment
instance MABIMax100FirstAxis : DTDFVocab:Component [
    base:desc "First axis of the MABI MAX 100 six‑axis industrial robot, comprising a permanent‑magnet synchronous motor, gear transmission and cycloidal gearbox"
]

instance RobotCellEnvironment : DTDFVocab:Environment [
    base:contains MABIMax100FirstAxis, MotorMountedEncoder, GearboxEncoder, RobotControllerInterface
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous, real‑time operation during robot run‑time; data are acquired and processed on‑line as the robot moves, enabling immediate identification of friction changes."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A purpose‑driven digital shadow comprising a singleton Purpose class (FrictionDerivation), an Asset class (Mabi), multiple DataTrace classes (e.g., I_M, r_M, r_G, r_out, ^r_M, ^r_G, ^r_out), Processing components (Simulation_M, Simulation_GW, Simulation_GB) that execute Simulink models, and metadata linking all traces to their sources, forming an integrated virtual replica of the first robot axis."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital shadow is instantiated and used in the operated phase of the robot, i.e., during runtime, to monitor and improve motion accuracy; engineering models are created beforehand but the primary activity is during operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability is ensured by linking each DataTrace to its originating source and processing component; engineering models provide contextual asset information; simulation models are executable and calibrated against live measurements; this fine‑grained traceability supports verification of model accuracy and assessment of uncertainties in friction identification."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted from the robot to the digital shadow over MQTT; Asset Administration Shells (AAS) are used for structuring asset information; the digital shadow consumes these streams and produces processed traces for the dashboard."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation uses the Industry 4.0 Asset Administration Shell (AAS) standard for asset description and SysML as a modelling standard; MQTT is used as a de‑facto protocol for IoT data exchange."
]
